        case .bootstrap:
            writeInt(&buf, Int32(1))
        
        
        case .createWallet:
            writeInt(&buf, Int32(2))
        
        
        case let .restoreWallet(mnemonic):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(mnemonic, into: &buf)
            
        
        case let .replaceWallet(mnemonic):
